mapper.select:
SELECT id, user_id, title, last_message_at, create_time, update_time
FROM ai_career_plan.chat_conversation
WHERE id = #{id}

SELECT id, user_id, title, last_message_at, create_time, update_time
FROM ai_career_plan.chat_conversation
WHERE user_id = #{userId}

    AND id < #{cursor}

ORDER BY last_message_at DESC NULLS LAST, id DESC
LIMIT #{limit}

mapper.update:
UPDATE ai_career_plan.chat_conversation
SET title = #{title}, update_time = CURRENT_TIMESTAMP
